export default function HomePage({ mode }) {
  const dispatch = useDispatch();
  const { state } = useLocation();
  const rePass = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)[A-Za-z\d@$!%*#?&]{8,}$/;

  const RegisterSchema = Yup.object().shape({
    email: Yup.string()
      .email("Email must be a valid email address")
      .required("Email is required"),
    password: Yup.string()
      .required("Password is required")

      .matches(
        rePass,
        "Minimum eight characters, at least one uppercase letter, one lowercase letter, one number"
      ),

    confirmPass: Yup.string()
      .required("confirm password is required")
      .oneOf([Yup.ref("password"), null], "Passwords must match"),
  });

  const formik = useFormik({
    initialValues: {
      email: state?.email || "",
      password: "",
      confirmPass: "",
    },
    validationSchema: RegisterSchema,
    onSubmit: async (values, { setErrors, setSubmitting }) => {
      setSubmitting(true);
      dispatch(
        updateFeedback({
          loading: true,
        })
      );

      if (!state?.email)
        axios
          .post(`${api.protocol}${api.baseUrl}${api.SendVerifyMail}`, {
            email: values.email,
          })
          .then((response) => {
            dispatch(
              updateOnboarding({
                authType: "1",
                email: values.email,
                password: values.password,
              })
            );

            {
              !state?.email &&
                dispatch(
                  updateFeedback({
                    loading: false,
                    snackbar: true,
                    message: "Verification mail sent to your email!",
                    severity: "success",
                  })
                );
            }
            navigate(
              `/onboarding/${mode == "client" ? "client/" : ""}${
                state?.email ? "info" : "verification"
              }`,
              { state }
            );
          })
          .catch((error) => {
            if (error.response.status === 406)
              return dispatch(
                updateFeedback({
                  loading: false,
                  snackbar: true,
                  message: "Acccount with give email address already exists!",
                  severity: "error",
                })
              );
            else
              return dispatch(
                updateFeedback({
                  loading: false,
                  snackbar: true,
                  message: "Oops caught some error! Please try again",
                  severity: "error",
                })
              );
          });
      else {
        dispatch(
          updateFeedback({
            loading: false,
          })
        );
        dispatch(
          updateOnboarding({
            authType: 1,
            email: values.email,
            password: values.password,
            token: state?.token,
          })
        );
        navigate(
          `/onboarding/${mode == "client" ? "client/" : ""}${
            state?.email ? "info" : "verification"
          }`,
          { state }
        );
      }
    },
  });
  const modalContext = useConfirmationModalContext();
  const responseGoogle = (res) => {
    dispatch(
      updateFeedback({
        loading: true,
      })
    );
    axios
      .get(
        `${api.protocol}${api.baseUrl}${api.checkUserExistence}email=${res?.profileObj.email}`
      )
      .then((response) => {
        dispatch(
          updateFeedback({
            loading: false,
          })
        );
        if (response.data.authType.includes("gmail")) {
          dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "User already exists",
              severity: "error",
            })
          );
        } else {
          modalContext
            .showConfirmationModal(
              "Alert!",
              "This email is already registered with other auth provide , would you like to link gmail with this account?",
              "Yes",
              "No"
            )
            .then((result) => {
              if (result) {
                dispatch(
                  updateFeedback({
                    loading: true,
                  })
                );
                axios
                  .patch(`${api.protocol}${api.baseUrl}${api.updateAuth}`, {
                    email: response.data.email,
                    authType: "gmail",
                  })
                  .then((response) => {
                    updateFeedback({
                      loading: false,
                      snackbar: true,
                      message: "Account linked with gmail , login to continue",
                      severity: "success",
                    });
                  });
              } else {
              }
            });
        }
      })
      .catch((error) => {
        dispatch(
          updateFeedback({
            loading: false,
          })
        );
        if (error.response.status === 404) {
          dispatch(
            updateOnboarding({
              name: res?.profileObj.name,
              email: res?.profileObj.email,
              profilePic: res?.profileObj.imageUrl,
              token: res.tokenId,
              authType: "gmail",
            })
          );
          navigate(`/onboarding/${mode == "client" ? "client/" : ""}info`);
        }
      });
  };

  const navigate = useNavigate();
  const {
    errors,
    touched,
    handleSubmit,
    isSubmitting,
    getFieldProps,
    setFieldValue,
    values,
  } = formik;
  return (
    <Page title="The starting point for your next fitness gig">
      <FormikProvider value={formik}>
        <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
          <Container>
            <HeaderBase>
              {" "}
              <Header
                title={"Create new account"}
                onClose={() => navigate("/", { state })}
              />
            </HeaderBase>
            <Content>
              <Box
                display={"flex"}
                flexDirection={"column"}
                alignItems={"center"}
                flexGrow={"1"}
              >
                <Typography variant="h2" color={"primary"} sx={{ my: 6 }}>
                  Hello {mode == "client" ? "athlete" : "coach"} 👋
                </Typography>

                <Stack spacing={2} sx={{ width: "100%" }}>
                  <TextField
                    fullWidth
                    disabled={state?.email}
                    placeholder=""
                    clabel={
                      <Typography variant="subtitle1">
                        Your email address
                      </Typography>
                    }
                    {...getFieldProps("email")}
                    error={Boolean(touched.email && errors.email)}
                    helperText={touched.email && errors.email}
                  />
                  <PasswordField
                    clabel={
                      <Typography variant="subtitle1">Password</Typography>
                    }
                    fullWidth
                    placeholder=""
                    {...getFieldProps("password")}
                    error={Boolean(touched.password && errors.password)}
                    helperText={touched.password && errors.password}
                  />
                  <PasswordField
                    clabel={
                      <Typography variant="subtitle1">
                        Confirm Password
                      </Typography>
                    }
                    fullWidth
                    placeholder=""
                    {...getFieldProps("confirmPass")}
                    error={Boolean(touched.confirmPass && errors.confirmPass)}
                    helperText={touched.confirmPass && errors.confirmPass}
                  />
                </Stack>
                <Box mt={4} mb={4} width={"100%"}>
                  {/* <GoogleLogin
                    clientId="20299471486-m23pkgk770a4vq3dgjh8uc9k180cpc98.apps.googleusercontent.com"
                    render={(renderProps) => (
                      <SocialButton
                        sx={{ borderColor: "rgba(149, 163, 184, 1)" }}
                        onClick={renderProps.onClick}
                        disabled={renderProps.disabled}
                        fullWidth
                        startIcon={
                          <Iconify
                            icon={"flat-color-icons:google"}
                            width={24}
                            height={24}
                          />
                        }
                        endIcon={<Box width={24} height={24}></Box>}
                      >
                      
                        <Typography variant="h6" color="text.primary">
                          Sign up with google
                        </Typography>
                      </SocialButton>
                    )}
                    buttonText="Login"
                    onSuccess={responseGoogle}
                    onFailure={(res) => {
                      console.log(res);
                    }}
                    cookiePolicy={"single_host_origin"}
                  /> */}
                </Box>
              </Box>
            </Content>
            <FooterBase>
              <Footer next />
            </FooterBase>
          </Container>
        </Form>
      </FormikProvider>
    </Page>
  );
}
